import{Vector}from"../utils/vector";class Shape{constructor(options){this.id=null,this.center=Vector.zero(),this.options=options,this.rotation=0,this.selected=!1}static getHitRGB(id){return`rgb(${(16711680&id)>>16},${(65280&id)>>8},${255&id})`}serialize(){throw new Error("serialize method must be implemented")}set setCenter({center:center=Vector.zero(),save:save=!0}){this.center=center}set setWidth(width){throw new Error("setWidth method must be implemented")}set setHeight(height){throw new Error("setHeight method must be implemented")}set setSize({width:width,height:height,save:save=!0}){this.setWidth=width,this.setHeight=height}set setRotation({angle:angle,save:save=!0}){this.rotation=angle}set setOptions({options:options,save:save=!0}){for(const key in options)this.options.hasOwnProperty(key)&&(this.options[key]=options[key])}reCenter(){const points=this.getPoints();this.center=Vector.mid(points);for(const point of points){point=Vector.subtract(point,this.center)}this.setPoints(points)}applyHitRegionStyles(ctx,dilaion=10){const rgb=Shape.getHitRGB(this.id),{lineCap:lineCap,lineJoin:lineJoin,stroke:stroke}=this.options;ctx.lineCap=lineCap,ctx.lineJoin=lineJoin,ctx.fillStyle=rgb,ctx.strokeStyle=rgb,ctx.lineWidth=stroke.width+dilaion,ctx.fill(),stroke.enable&&ctx.stroke()}getPoints(){throw new Error("getPoints method must be implemented")}setPoints(){throw new Error("getPoints method must be implemented")}draw(ctx){throw new Error("draw method must be implemented")}}